import { useEffect, useState } from 'react';
import { Navigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { contentApi } from '../services/api';
import './Admin.css';

const EMPTY_FORM = {
  type: 'video',
  title: '',
  description: '',
  thumbnail: '',
  videoUrl: '',
  content: '',
  featured: false,
  trending: false,
};

export default function AdminDashboard() {
  const { admin, loading: authLoading } = useAuth();
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(true);
  const [form, setForm] = useState(EMPTY_FORM);
  const [showForm, setShowForm] = useState(false);
  const [saving, setSaving] = useState(false);
  const [message, setMessage] = useState('');

  const loadItems = () => {
    contentApi
      .getAll()
      .then(setItems)
      .catch(console.error)
      .finally(() => setLoading(false));
  };

  useEffect(() => {
    if (admin) loadItems();
  }, [admin]);

  if (authLoading) return <div className="page-loading">Loading...</div>;
  if (!admin) return <Navigate to="/admin/login" replace />;

  const handleToggle = async (id, field) => {
    try {
      const updated = await contentApi.toggle(id, field);
      setItems((prev) => prev.map((i) => (i.id === id ? updated : i)));
      setMessage(`${field} toggled for "${updated.title}"`);
      setTimeout(() => setMessage(''), 3000);
    } catch (err) {
      setMessage(err.message);
    }
  };

  const handleDelete = async (id, title) => {
    if (!window.confirm(`Delete "${title}"?`)) return;
    try {
      await contentApi.delete(id);
      setItems((prev) => prev.filter((i) => i.id !== id));
      setMessage('Content deleted');
      setTimeout(() => setMessage(''), 3000);
    } catch (err) {
      setMessage(err.message);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      const created = await contentApi.create(form);
      setItems((prev) => [created, ...prev]);
      setForm(EMPTY_FORM);
      setShowForm(false);
      setMessage('Content created successfully');
      setTimeout(() => setMessage(''), 3000);
    } catch (err) {
      setMessage(err.message);
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="admin-page">
      <div className="admin-header">
        <div>
          <h1>Admin Dashboard</h1>
          <p>Manage videos, blogs, featured & trending status</p>
        </div>
        <button
          type="button"
          className="btn btn-primary"
          onClick={() => setShowForm(!showForm)}
        >
          {showForm ? 'Cancel' : '+ Add Content'}
        </button>
      </div>

      {message && <div className="admin-message">{message}</div>}

      {showForm && (
        <form className="admin-form" onSubmit={handleSubmit}>
          <h2>Add New Content</h2>
          <div className="form-row">
            <label>
              Type
              <select
                value={form.type}
                onChange={(e) => setForm({ ...form, type: e.target.value })}
              >
                <option value="video">Video</option>
                <option value="blog">Blog</option>
              </select>
            </label>
            <label>
              Title
              <input
                value={form.title}
                onChange={(e) => setForm({ ...form, title: e.target.value })}
                required
              />
            </label>
          </div>
          <label>
            Description
            <input
              value={form.description}
              onChange={(e) => setForm({ ...form, description: e.target.value })}
            />
          </label>
          <label>
            Thumbnail URL
            <input
              value={form.thumbnail}
              onChange={(e) => setForm({ ...form, thumbnail: e.target.value })}
              placeholder="https://..."
            />
          </label>
          {form.type === 'video' ? (
            <label>
              Video URL
              <input
                value={form.videoUrl}
                onChange={(e) => setForm({ ...form, videoUrl: e.target.value })}
                required
                placeholder="https://..."
              />
            </label>
          ) : (
            <label>
              Blog Content
              <textarea
                value={form.content}
                onChange={(e) => setForm({ ...form, content: e.target.value })}
                required
                rows={6}
              />
            </label>
          )}
          <div className="form-checks">
            <label className="checkbox-label">
              <input
                type="checkbox"
                checked={form.featured}
                onChange={(e) => setForm({ ...form, featured: e.target.checked })}
              />
              Featured
            </label>
            <label className="checkbox-label">
              <input
                type="checkbox"
                checked={form.trending}
                onChange={(e) => setForm({ ...form, trending: e.target.checked })}
              />
              Trending
            </label>
          </div>
          <button type="submit" className="btn btn-primary" disabled={saving}>
            {saving ? 'Saving...' : 'Create Content'}
          </button>
        </form>
      )}

      {loading ? (
        <div className="page-loading">Loading content...</div>
      ) : (
        <div className="admin-table-wrap">
          <table className="admin-table">
            <thead>
              <tr>
                <th>Title</th>
                <th>Type</th>
                <th>Featured</th>
                <th>Trending</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {items.map((item) => (
                <tr key={item.id}>
                  <td>
                    <strong>{item.title}</strong>
                    <br />
                    <small>{new Date(item.createdAt).toLocaleDateString()}</small>
                  </td>
                  <td>
                    <span className={`type-pill ${item.type}`}>{item.type}</span>
                  </td>
                  <td>
                    <button
                      type="button"
                      className={`toggle-btn ${item.featured ? 'on' : 'off'}`}
                      onClick={() => handleToggle(item.id, 'featured')}
                      title="Toggle featured (admin only)"
                    >
                      {item.featured ? 'ON' : 'OFF'}
                    </button>
                  </td>
                  <td>
                    <button
                      type="button"
                      className={`toggle-btn ${item.trending ? 'on' : 'off'}`}
                      onClick={() => handleToggle(item.id, 'trending')}
                      title="Toggle trending (admin only)"
                    >
                      {item.trending ? 'ON' : 'OFF'}
                    </button>
                  </td>
                  <td>
                    <button
                      type="button"
                      className="delete-btn"
                      onClick={() => handleDelete(item.id, item.title)}
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}
